import React, { useEffect, useState } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import { ArrowLeft, Plus, BedDouble, Car, Bus, Map, Ticket, UtensilsCrossed, Plane, Shield, Pencil, X } from 'lucide-react'
import { supabase } from '../lib/supabase'
import { useAuth, Profile } from '../lib/auth'
import { useToast } from '../lib/toast'
import { listProfiles } from '../lib/team'
import { Group, listGroups } from '../lib/groups'
import DocumentsPanel from '../components/DocumentsPanel'
import ActivityPanel from '../components/ActivityPanel'
import TasksPanel from '../components/TasksPanel'
import { logActivity } from '../lib/activity'
import { getCachedSettings, loadSettings } from '../lib/companySettings'
import FinancialPanel from '../components/FinancialPanel'
import InvoicePanel from '../components/InvoicePanel'
import { formatMoney } from '../lib/currency'
import { listPayments, sumPayments } from '../lib/payments'
import { openWhatsApp, quoteMessage, voucherMessage, generalMessage } from '../lib/whatsapp'
import { MessageCircle } from 'lucide-react'

const LOGO_SRC = 'data:image/png;base64,'

const BOOKING_TYPES = [
  { key: 'hotel',     label: 'Hotel',      icon: BedDouble,       color: '#185FA5', bg: '#E6F1FB' },
  { key: 'car_rental',label: 'Car Rental', icon: Car,             color: '#0F6E56', bg: '#E1F5EE' },
  { key: 'transfer',  label: 'Transfer',   icon: Bus,             color: '#854F0B', bg: '#FAEEDA' },
  { key: 'day_trip',  label: 'Day Trip',   icon: Map,             color: '#3B6D11', bg: '#EAF3DE' },
  { key: 'entrance',  label: 'Entrance',   icon: Ticket,          color: '#534AB7', bg: '#EEEDFE' },
  { key: 'meals',     label: 'Meals',      icon: UtensilsCrossed, color: '#993556', bg: '#FBEAF0' },
  { key: 'flight',    label: 'Flights',    icon: Plane,           color: '#0C447C', bg: '#B5D4F4' },
  { key: 'vip',       label: 'VIP',        icon: Shield,          color: '#B8860B', bg: '#FFF8E6' },
]

const STATUS_STEPS = ['inquiry','quoted','confirmed','paid','voucher_sent','completed']
const STATUS_LABELS: Record<string,string> = {
  inquiry:'Inquiry', quoted:'Quoted', confirmed:'Confirmed',
  paid:'Paid', voucher_sent:'Voucher Sent', completed:'Completed', cancelled:'Cancelled'
}

const BOOKING_COLORS: Record<string,{color:string;label:string}> = {
  hotel:      { color: '#185FA5', label: 'Hotel Booking' },
  car_rental: { color: '#0F6E56', label: 'Car Rental' },
  transfer:   { color: '#854F0B', label: 'Transfer' },
  day_trip:   { color: '#3B6D11', label: 'Day Trip' },
  entrance:   { color: '#534AB7', label: 'Entrance Fees' },
  meals:      { color: '#993556', label: 'Meals & Restaurant' },
  flight:     { color: '#0C447C', label: 'Flight Booking' },
  vip:        { color: '#B8860B', label: 'VIP Airport Service' },
}

export default function ClientCard() {
  const { id } = useParams()
  const navigate = useNavigate()
  const [client, setClient] = useState<any>(null)
  const [travelers, setTravelers] = useState<any[]>([])
  const [bookings, setBookings] = useState<any[]>([])
  const [activeType, setActiveType] = useState('hotel')
  const [showNewBooking, setShowNewBooking] = useState(false)
  const [editingBooking, setEditingBooking] = useState<any>(null)
  const [loading, setLoading] = useState(true)
  const [voucherBooking, setVoucherBooking] = useState<any>(null)
  const { profile, user } = useAuth()
  const toast = useToast()
  const [agents, setAgents] = useState<Profile[]>([])
  const [groups, setGroups] = useState<Group[]>([])
  const [showEditClient, setShowEditClient] = useState(false)
  const [showAddTraveler, setShowAddTraveler] = useState(false)
  const [activityKey, setActivityKey] = useState(0)
  const bumpActivity = () => setActivityKey(k => k + 1)

  async function reloadData() {
    const [{ data: c }, { data: tr }, { data: b }] = await Promise.all([
      supabase.from('clients').select('*').eq('id', id).single(),
      supabase.from('travelers').select('*').eq('client_id', id),
      supabase.from('bookings').select('*').eq('client_id', id).order('created_at', { ascending: false }),
    ])
    setClient(c); setTravelers(tr || []); setBookings(b || [])
  }

  useEffect(() => {
    async function load() {
      const [{ data: c }, { data: tr }, { data: b }] = await Promise.all([
        supabase.from('clients').select('*').eq('id', id).single(),
        supabase.from('travelers').select('*').eq('client_id', id),
        supabase.from('bookings').select('*').eq('client_id', id).order('created_at', { ascending: false }),
      ])
      setClient(c); setTravelers(tr || []); setBookings(b || [])
      setLoading(false)
    }
    load()
  }, [id])

  // Admins can see the team to reassign client ownership
  useEffect(() => {
    if (profile?.role === 'admin') {
      listProfiles().then(setAgents)
    }
  }, [profile])

  // Load groups for the group selector
  useEffect(() => {
    listGroups().then(setGroups)
  }, [])

  async function reassignOwner(newOwnerId: string) {
    const value = newOwnerId || null
    await supabase.from('clients').update({ owner_id: value }).eq('id', id)
    setClient((c: any) => ({ ...c, owner_id: value }))
  }

  async function linkGroup(groupId: string | null) {
    await supabase.from('clients').update({ group_id: groupId }).eq('id', id)
    setClient((c: any) => ({ ...c, group_id: groupId }))
    toast.success(groupId ? 'Linked to group' : 'Removed from group')
  }

  if (loading) return <div style={{ padding: 40, textAlign: 'center', color: '#aaa' }}>Loading...</div>
  if (!client) return <div style={{ padding: 40, textAlign: 'center', color: '#aaa' }}>Client not found</div>

  const activeBookings = bookings.filter(b => b.type === activeType)
  const initials = client.full_name?.split(' ').map((n: string) => n[0]).join('').slice(0, 2)
  const allTravelers = [
    { full_name: client.full_name, is_lead: true, type: 'adult', passport_number: client.passport_number, nationality: client.nationality, date_of_birth: client.date_of_birth },
    ...travelers
  ]

  return (
    <>
      {voucherBooking && (
        <VoucherModal booking={voucherBooking} client={client} travelers={allTravelers} onClose={() => setVoucherBooking(null)} />
      )}
      {showEditClient && (
        <EditClientModal client={client} onClose={() => setShowEditClient(false)} onSaved={async () => { setShowEditClient(false); await reloadData(); await logActivity(id!, 'edit', 'Client details updated', user?.id || null, profile?.full_name || null); bumpActivity(); toast.success('Client updated') }} />
      )}
      {showAddTraveler && (
        <AddTravelerModal clientId={id!} onClose={() => setShowAddTraveler(false)} onSaved={async (name?: string) => { setShowAddTraveler(false); await reloadData(); await logActivity(id!, 'traveler', `Traveler added${name ? `: ${name}` : ''}`, user?.id || null, profile?.full_name || null); bumpActivity(); toast.success('Traveler added') }} />
      )}
      <div style={{ padding: 24 }}>
        <div style={{ display: 'flex', alignItems: 'center', marginBottom: 16 }}>
          <button onClick={() => navigate('/clients')} style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#888', display: 'flex', alignItems: 'center', gap: 4, fontSize: 13 }}>
            <ArrowLeft size={16} /> Clients
          </button>
        </div>

        <div style={{ display: 'grid', gridTemplateColumns: '300px 1fr', gap: 16 }}>
          {/* CLIENT CARD */}
          <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
            <div style={{ background: '#fff', borderRadius: 12, border: '0.5px solid #e5e5e5', overflow: 'hidden' }}>
              <div style={{ background: '#1a2a3a', padding: '14px 16px', display: 'flex', alignItems: 'center', gap: 10 }}>
                <div style={{ width: 40, height: 40, borderRadius: '50%', background: '#E6F1FB', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 14, fontWeight: 600, color: '#185FA5', flexShrink: 0 }}>{initials}</div>
                <div style={{ flex: 1 }}>
                  <div style={{ color: '#fff', fontSize: 14, fontWeight: 600 }}>{client.full_name}</div>
                  <div style={{ color: '#f5c842', fontSize: 11, marginTop: 2, fontWeight: 600 }}>File {client.file_number}</div>
                </div>
                <button onClick={() => setShowEditClient(true)} title="Edit client" style={{ background: 'rgba(255,255,255,0.12)', border: 'none', borderRadius: 7, padding: 6, cursor: 'pointer', display: 'flex' }}>
                  <Pencil size={13} color="#f5c842" />
                </button>
              </div>
              <div style={{ padding: 14 }}>
                {[['Phone', client.phone],['Email', client.email],['Passport', client.passport_number],['Date of Birth', client.date_of_birth],['Nationality', client.nationality],['Preferences', client.preferences]].filter(([,v]) => v).map(([label, val]) => (
                  <div key={label} style={{ marginBottom: 8 }}>
                    <div style={{ fontSize: 9, color: '#aaa', fontWeight: 500, textTransform: 'uppercase', letterSpacing: '0.4px', marginBottom: 2 }}>{label}</div>
                    <div style={{ fontSize: 12, color: '#333', background: '#fafafa', borderRadius: 6, padding: '4px 8px', border: '0.5px solid #eee' }}>{val}</div>
                  </div>
                ))}
                {client.phone && (
                  <button
                    onClick={() => openWhatsApp(client.phone, generalMessage(client.full_name, getCachedSettings().company_name))}
                    style={{ width: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6, background: '#E1F5EE', color: '#0F6E56', border: 'none', borderRadius: 7, padding: '8px 10px', cursor: 'pointer', fontWeight: 600, fontSize: 12, marginBottom: 10 }}
                  >
                    <MessageCircle size={14} /> Message on WhatsApp
                  </button>
                )}
                <span style={{ fontSize: 11, padding: '3px 10px', borderRadius: 20, background: client.status === 'lead' ? '#E1F5EE' : client.status === 'active' ? '#E6F1FB' : '#F1EFE8', color: client.status === 'lead' ? '#0F6E56' : client.status === 'active' ? '#185FA5' : '#5F5E5A', fontWeight: 500 }}>
                  {client.status === 'lead' ? 'Lead' : client.status === 'active' ? 'Active' : 'Past'}
                </span>
                {profile?.role === 'admin' && (
                  <div style={{ marginTop: 12 }}>
                    <div style={{ fontSize: 9, color: '#aaa', fontWeight: 500, textTransform: 'uppercase', letterSpacing: '0.4px', marginBottom: 4 }}>Assigned Agent</div>
                    <select
                      value={client.owner_id || ''}
                      onChange={e => reassignOwner(e.target.value)}
                      style={{ width: '100%', fontSize: 12, padding: '5px 8px', borderRadius: 6, border: '0.5px solid #d0d0d0', background: '#fafafa', cursor: 'pointer', outline: 'none' }}
                    >
                      <option value="">Unassigned</option>
                      {agents.map(a => (
                        <option key={a.id} value={a.id}>{a.full_name} ({a.role})</option>
                      ))}
                    </select>
                  </div>
                )}

                {/* GROUP LINK */}
                <div style={{ marginTop: 12 }}>
                  <div style={{ fontSize: 9, color: '#aaa', fontWeight: 500, textTransform: 'uppercase', letterSpacing: '0.4px', marginBottom: 4 }}>Group</div>
                  <select
                    value={client.group_id || ''}
                    onChange={e => linkGroup(e.target.value || null)}
                    style={{ width: '100%', fontSize: 12, padding: '5px 8px', borderRadius: 6, border: '0.5px solid #d0d0d0', background: '#fafafa', cursor: 'pointer', outline: 'none' }}
                  >
                    <option value="">No group</option>
                    {groups.map(g => (
                      <option key={g.id} value={g.id}>{g.name}</option>
                    ))}
                  </select>
                  {client.group_id && (
                    <button onClick={() => navigate(`/groups/${client.group_id}`)} style={{ marginTop: 5, fontSize: 11, color: '#534AB7', background: 'none', border: 'none', cursor: 'pointer', padding: 0 }}>
                      Open group →
                    </button>
                  )}
                </div>
              </div>
            </div>

            {/* TRAVELERS */}
            <div style={{ background: '#fff', borderRadius: 12, border: '0.5px solid #e5e5e5', padding: 14 }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 10 }}>
                <span style={{ fontSize: 12, fontWeight: 600 }}>Travelers ({allTravelers.length})</span>
                <button onClick={() => setShowAddTraveler(true)} style={{ fontSize: 10, color: '#0F6E56', background: '#E1F5EE', border: '0.5px solid #5DCAA5', borderRadius: 20, padding: '2px 8px', cursor: 'pointer' }}>+ Add</button>
              </div>
              {allTravelers.map((tr, i) => (
                <div key={i} style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '6px 8px', background: '#fafafa', borderRadius: 8, marginBottom: 5, border: '0.5px solid #eee' }}>
                  <div style={{ width: 20, height: 20, borderRadius: '50%', background: i === 0 ? '#1a2a3a' : '#E6F1FB', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 9, color: i === 0 ? '#f5c842' : '#185FA5', fontWeight: 600 }}>{i + 1}</div>
                  <div style={{ flex: 1 }}>
                    <div style={{ fontSize: 12, fontWeight: 500 }}>{tr.full_name}</div>
                    <div style={{ fontSize: 10, color: '#888' }}>{tr.is_lead ? 'Lead' : tr.type === 'child' ? `Child · Age ${tr.age}` : 'Adult'}</div>
                  </div>
                </div>
              ))}
            </div>

            {/* DOCUMENTS */}
            <DocumentsPanel clientId={id!} onUploaded={async (fileName, category) => { await logActivity(id!, 'document', `Document uploaded: ${fileName} (${category})`, user?.id || null, profile?.full_name || null); bumpActivity() }} />

            {/* TASKS */}
            <TasksPanel clientId={id!} />

            {/* ALL BOOKINGS SUMMARY */}
            {bookings.length > 0 && (
              <div style={{ background: '#fff', borderRadius: 12, border: '0.5px solid #e5e5e5', overflow: 'hidden' }}>
                <div style={{ padding: '10px 14px', borderBottom: '0.5px solid #f0f0f0', fontSize: 12, fontWeight: 600 }}>All Bookings in File</div>
                {bookings.map(b => {
                  const bt = BOOKING_TYPES.find(bt => bt.key === b.type)
                  return (
                    <div key={b.id} onClick={() => setActiveType(b.type)} style={{ padding: '8px 14px', display: 'flex', alignItems: 'center', gap: 8, borderBottom: '0.5px solid #f8f8f8', cursor: 'pointer' }}
                      onMouseEnter={e => (e.currentTarget.style.background = '#fafafa')}
                      onMouseLeave={e => (e.currentTarget.style.background = 'transparent')}>
                      {bt && <div style={{ background: bt.bg, borderRadius: 6, padding: 5 }}><bt.icon size={12} color={bt.color} /></div>}
                      <div style={{ flex: 1, minWidth: 0 }}>
                        <div style={{ fontSize: 11, fontWeight: 500, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{b.service_name}</div>
                        <div style={{ fontSize: 10, color: '#888' }}>{formatMoney(b.total_price, b.currency)}</div>
                      </div>
                      <span style={{ fontSize: 9, padding: '1px 6px', borderRadius: 10, background: '#f0f0f0', color: '#555', whiteSpace: 'nowrap' }}>{STATUS_LABELS[b.status] || b.status}</span>
                    </div>
                  )
                })}
              </div>
            )}
          </div>

          {/* RIGHT PANEL */}
          <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>
            {/* BOOKING TYPE TABS */}
            <div style={{ background: '#fff', borderRadius: 12, border: '0.5px solid #e5e5e5', padding: '10px 12px' }}>
              <div style={{ fontSize: 9, fontWeight: 600, color: '#aaa', marginBottom: 8, textTransform: 'uppercase', letterSpacing: '.5px' }}>Booking Type</div>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(8,1fr)', gap: 5 }}>
                {BOOKING_TYPES.map(({ key, label, icon: Icon, color, bg }) => (
                  <button key={key} onClick={() => { setActiveType(key); setShowNewBooking(false) }}
                    style={{ border: activeType === key ? `2px solid ${color}` : '0.5px solid #e5e5e5', borderRadius: 10, padding: '8px 4px', textAlign: 'center', cursor: 'pointer', background: activeType === key ? bg : '#fff', transition: 'all 0.15s' }}>
                    <Icon size={16} color={activeType === key ? color : '#aaa'} style={{ display: 'block', margin: '0 auto 3px' }} />
                    <span style={{ fontSize: 9, color: activeType === key ? color : '#888', fontWeight: activeType === key ? 600 : 400 }}>{label}</span>
                  </button>
                ))}
              </div>
            </div>

            {/* BOOKINGS PANEL */}
            <div style={{ background: '#fff', borderRadius: 12, border: '0.5px solid #e5e5e5', overflow: 'hidden' }}>
              <div style={{ padding: '12px 16px', borderBottom: '0.5px solid #f0f0f0', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <span style={{ fontSize: 14, fontWeight: 600 }}>{BOOKING_TYPES.find(b => b.key === activeType)?.label} Bookings</span>
                <button onClick={() => setShowNewBooking(true)} style={{ display: 'flex', alignItems: 'center', gap: 5, padding: '6px 14px', background: '#1a2a3a', color: '#fff', border: 'none', borderRadius: 8, cursor: 'pointer', fontSize: 12, fontWeight: 500 }}>
                  <Plus size={13} /> New Booking
                </button>
              </div>

              {showNewBooking && (
                <BookingForm type={activeType} clientId={id!} fileNumber={client.file_number} travelers={allTravelers}
                  onSave={async (b: any) => {
                    const { data, error } = await supabase.from('bookings').insert(b).select().single()
                    if (error) { toast.error('Could not save booking'); return }
                    if (data) { setBookings(bk => [data, ...bk]); setShowNewBooking(false)
                      await logActivity(id!, 'booking', `New ${BOOKING_TYPES.find(bt => bt.key === data.type)?.label || data.type} booking: ${data.service_name || ''}`, user?.id || null, profile?.full_name || null)
                      bumpActivity()
                      toast.success('Booking created')
                    }
                  }}
                  onCancel={() => setShowNewBooking(false)}
                />
              )}

              {activeBookings.length === 0 && !showNewBooking ? (
                <div style={{ padding: 30, textAlign: 'center', color: '#aaa', fontSize: 13 }}>
                  No {BOOKING_TYPES.find(b => b.key === activeType)?.label} bookings yet.
                </div>
              ) : activeBookings.map(b => (
                editingBooking?.id === b.id ? (
                  <BookingForm key={b.id} type={b.type} clientId={id!} fileNumber={client.file_number} travelers={allTravelers} existing={b}
                    onSave={async (upd: any) => {
                      const { data, error } = await supabase.from('bookings').update(upd).eq('id', b.id).select().single()
                      if (error) { toast.error('Could not save changes'); return }
                      if (data) {
                        setBookings(bks => bks.map(bk => bk.id === b.id ? data : bk))
                        setEditingBooking(null)
                        await logActivity(id!, 'edit', `Booking updated: ${data.service_name || data.type}`, user?.id || null, profile?.full_name || null)
                        bumpActivity()
                        toast.success('Booking updated')
                      }
                    }}
                    onCancel={() => setEditingBooking(null)}
                  />
                ) : (
                <BookingRow key={b.id} booking={b} client={client}
                  onVoucher={() => setVoucherBooking(b)}
                  onEdit={() => setEditingBooking(b)}
                  onDuplicate={async () => {
                    const { id: _id, created_at: _ca, ...rest } = b
                    const copy = { ...rest, status: 'inquiry', service_name: `${b.service_name || b.type} (copy)`, deposit_paid: 0, supplier_id: null, cost_price: null }
                    const { data, error } = await supabase.from('bookings').insert(copy).select().single()
                    if (error) { toast.error('Could not duplicate booking'); return }
                    if (data) {
                      setBookings(bks => [data, ...bks])
                      await logActivity(id!, 'booking', `Booking duplicated: ${data.service_name || data.type}`, user?.id || null, profile?.full_name || null)
                      bumpActivity()
                      toast.success('Booking duplicated')
                    }
                  }}
                  onFinanceChange={() => reloadData()}
                  onStatusChange={async (newStatus: string) => {
                    await supabase.from('bookings').update({ status: newStatus }).eq('id', b.id)
                    setBookings(bks => bks.map(bk => bk.id === b.id ? { ...bk, status: newStatus } : bk))
                    await logActivity(id!, 'status', `${b.service_name || 'Booking'} → ${STATUS_LABELS[newStatus] || newStatus}`, user?.id || null, profile?.full_name || null)
                    bumpActivity()
                    toast.success(`Status: ${STATUS_LABELS[newStatus] || newStatus}`)
                  }}
                />
                )
              ))}
            </div>

            {/* ACTIVITY TIMELINE */}
            <ActivityPanel clientId={id!} refreshKey={activityKey} />
          </div>
        </div>

        {/* INVOICES — full width */}
        <div style={{ marginTop: 16 }}>
          <InvoicePanel clientId={id!} client={client} bookings={bookings} />
        </div>
      </div>
    </>
  )
}

/* ─── VOUCHER MODAL ─────────────────────────────────────────────────────── */
function VoucherModal({ booking: b, client, travelers, onClose }: any) {
  const [company, setCompany] = useState(getCachedSettings())
  const [payments, setPayments] = useState<any[]>([])
  const [showPrices, setShowPrices] = useState(true)
  useEffect(() => { loadSettings().then(setCompany) }, [])
  useEffect(() => { listPayments(b.id).then(setPayments) }, [b.id])
  // Stable voucher number derived from the booking id (not Date.now())
  const vchNum = `VCH-${new Date().getFullYear()}-${String(b.id).replace(/[^0-9]/g, '').slice(-4).padStart(4, '0')}`
  const bc = BOOKING_COLORS[b.type] || { color: '#1a2a3a', label: b.type }
  const stepIdx = STATUS_STEPS.indexOf(b.status)
  const isPaid = ['paid','voucher_sent','completed'].includes(b.status)
  // Use real recorded payments; fall back to the legacy deposit field if none exist
  const paidAmount = payments.length > 0 ? sumPayments(payments) : (Number(b.deposit_paid) || 0)
  const balanceNum = (Number(b.total_price) || 0) - paidAmount
  const fmt = (d: string) => d ? new Date(d).toLocaleDateString('en-GB', { day:'2-digit', month:'long', year:'numeric' }) : ''

  const s = {
    overlay: { position:'fixed' as const, inset:0, background:'rgba(0,0,0,.7)', zIndex:1000, overflow:'auto', padding:20, direction:'ltr' as const, textAlign:'left' as const },
    page: { background:'#fff', width:'100%', maxWidth:794, margin:'0 auto', fontFamily:'-apple-system,BlinkMacSystemFont,Segoe UI,sans-serif', fontSize:11, color:'#1a1a1a', boxShadow:'0 4px 24px rgba(0,0,0,.2)' },
    hdr: { background:'#1a2a3a', padding:'12px 20px', display:'flex' as const, alignItems:'center' as const, justifyContent:'space-between' as const },
    clientStrip: { background:'#f0f4f8', borderBottom:'0.5px solid #dde3ea', padding:'7px 20px', display:'flex' as const, alignItems:'center' as const, gap:16 },
    statusBar: { background:'#1a2a3a', padding:'6px 20px', display:'flex' as const, alignItems:'center' as const },
    body: { padding:'14px 20px' },
    secHead: { fontSize:9, fontWeight:700 as const, color:'#1a2a3a', textTransform:'uppercase' as const, letterSpacing:'.5px', borderBottom:'1.5px solid #1a2a3a', paddingBottom:3, marginBottom:7, marginTop:10 },
    grid3: { display:'grid' as const, gridTemplateColumns:'1fr 1fr 1fr', gap:6, marginBottom:8 },
    lbl: { fontSize:8, color:'#888', textTransform:'uppercase' as const, letterSpacing:'.3px', display:'block' as const, marginBottom:1 },
    val: { fontSize:11, color:'#1a1a1a', fontWeight:500 as const, paddingBottom:2, borderBottom:'0.5px solid #e8e8e8' },
    th: { background:'#f0f4f8', fontSize:8, color:'#555', fontWeight:600 as const, textTransform:'uppercase' as const, padding:'4px 6px', textAlign:'left' as const, border:'0.5px solid #dde3ea' },
    td: { padding:'4px 6px', border:'0.5px solid #eee', color:'#1a1a1a', fontSize:10 },
    priceStrip: { background:'#f0f4f8', border:'0.5px solid #dde3ea', borderRadius:6, padding:'8px 12px', display:'flex' as const, marginBottom:10 },
    vchBox: { background:'#E6F1FB', border:'1.5px solid #85B7EB', borderRadius:8, padding:'12px 16px', display:'flex' as const, alignItems:'center' as const, justifyContent:'space-between' as const, marginBottom:12 },
    footer: { background:'#1a2a3a', padding:'7px 20px', display:'flex' as const, alignItems:'center' as const, justifyContent:'space-between' as const },
  }

  const details = b.details || {}

  return (
    <div style={s.overlay} id="voucher-print-root">
      <div style={{ maxWidth:860, margin:'0 auto' }}>
        <div style={{ display:'flex', gap:8, marginBottom:12, justifyContent:'flex-end', alignItems:'center' }} className="no-print">
          <label style={{ display:'flex', alignItems:'center', gap:6, fontSize:12, color:'#555', cursor:'pointer', marginRight:'auto' }}>
            <input type="checkbox" checked={showPrices} onChange={e => setShowPrices(e.target.checked)} />
            Include prices
          </label>
          {client.phone && (
            <button onClick={() => openWhatsApp(client.phone, isPaid
              ? voucherMessage({ clientName: client.full_name, serviceName: b.service_name, fileNumber: client.file_number, companyName: company.company_name })
              : quoteMessage({ clientName: client.full_name, serviceName: b.service_name, totalPrice: Number(b.total_price) || undefined, currency: b.currency, fileNumber: client.file_number, companyName: company.company_name }))}
              style={{ padding:'8px 18px', background:'#E1F5EE', color:'#0F6E56', border:'none', borderRadius:8, fontWeight:700, fontSize:13, cursor:'pointer', display:'flex', alignItems:'center', gap:6 }}>
              <MessageCircle size={15} /> Send on WhatsApp
            </button>
          )}
          <button onClick={() => window.print()} style={{ padding:'8px 18px', background:'#f5c842', border:'none', borderRadius:8, fontWeight:700, fontSize:13, cursor:'pointer' }}>🖨 Print / Save PDF</button>
          <button onClick={onClose} style={{ padding:'8px 16px', background:'#fff', border:'0.5px solid #ccc', borderRadius:8, fontSize:13, cursor:'pointer' }}>✕ Close</button>
        </div>

        <div style={s.page}>
          {/* Header */}
          <div style={s.hdr}>
            <div style={{ display:'flex', alignItems:'center', gap:12 }}>
              <img src={LOGO_SRC} style={{ height:48, width:'auto', objectFit:'contain' }} alt="EYT" />
              <div style={{ color:'#7899bb', fontSize:10 }}>{company.website} · {company.phone} · {company.email}</div>
            </div>
            <div style={{ textAlign:'right' }}>
              <div style={{ color:'#f5c842', fontSize:13, fontWeight:700, textTransform:'uppercase', letterSpacing:'.5px' }}>{isPaid ? `${bc.label} Voucher` : `${bc.label} Booking`}</div>
              <div style={{ color:'#aabbcc', fontSize:10, marginTop:2 }}>File: {client.file_number}</div>
              <div style={{ color:'#7899bb', fontSize:9, marginTop:1 }}>{isPaid ? 'Issued' : 'Date'}: {new Date().toLocaleDateString('en-GB',{day:'2-digit',month:'long',year:'numeric'})}</div>
            </div>
          </div>

          {/* Client strip */}
          <div style={s.clientStrip}>
            {[['Client', client.full_name],['Phone', client.phone],['Email', client.email],['Nationality', client.nationality]].map(([l,v]) => v ? (
              <div key={l}><span style={{ fontSize:8, color:'#888', textTransform:'uppercase', letterSpacing:'.4px', fontWeight:500, display:'block', marginBottom:1 }}>{l}</span><span style={{ fontSize:11, color:'#1a2a3a', fontWeight:500 }}>{v}</span></div>
            ) : null)}
            <div style={{ background:'#1a2a3a', color:'#f5c842', fontSize:10, fontWeight:700, padding:'3px 10px', borderRadius:12, marginLeft:'auto' }}>{client.file_number}</div>
          </div>

          {/* Status bar */}
          <div style={s.statusBar}>
            {STATUS_STEPS.map((step, i) => (
              <React.Fragment key={step}>
                <div style={{ display:'flex', flexDirection:'column', alignItems:'center', flex:1 }}>
                  <div style={{ width:18, height:18, borderRadius:'50%', display:'flex', alignItems:'center', justifyContent:'center', fontSize:8, fontWeight:600, border:`1.5px solid ${i<=stepIdx?'#1D9E75':'#3a5270'}`, background:i<stepIdx?'#1D9E75':i===stepIdx?'#E1F5EE':'#1a2a3a', color:i<stepIdx?'#fff':i===stepIdx?'#0F6E56':'#7899bb' }}>{i<stepIdx?'✓':i+1}</div>
                  <div style={{ fontSize:7, color:i<=stepIdx?'#9FE1CB':'#7899bb', marginTop:2, whiteSpace:'nowrap' }}>{STATUS_LABELS[step]}</div>
                </div>
                {i<STATUS_STEPS.length-1 && <div style={{ flex:1, height:1, background:i<stepIdx?'#1D9E75':'#3a5270', marginBottom:10 }} />}
              </React.Fragment>
            ))}
          </div>

          <div style={s.body}>
            {/* Voucher box */}
            {isPaid && (
              <div style={s.vchBox}>
                <div>
                  <div style={{ fontSize:10, color:'#185FA5', fontWeight:600 }}>✈ {bc.label} Voucher — Present to service provider</div>
                  <div style={{ fontSize:20, fontWeight:700, color:'#042C53', letterSpacing:2, fontFamily:'monospace', margin:'4px 0' }}>{vchNum}</div>
                  <div style={{ fontSize:9, color:'#378ADD' }}>Issued {new Date().toLocaleDateString('en-GB')} · Valid for service dates only</div>
                </div>
                <div style={{ width:56, height:56, background:'#fff', border:'0.5px solid #85B7EB', borderRadius:4, display:'flex', alignItems:'center', justifyContent:'center', fontSize:8, color:'#85B7EB', textAlign:'center' }}>QR<br/>Code</div>
              </div>
            )}

            {/* Booking details */}
            <div style={s.secHead}>{bc.label} Details</div>
            <div style={s.grid3}>
              <div><span style={s.lbl}>Service</span><div style={{ ...s.val, fontWeight:700, fontSize:13 }}>{b.service_name}</div></div>
              {(b.check_in||b.pickup_date) && <div><span style={s.lbl}>{b.type==='hotel'?'Check-in':'Date'}</span><div style={s.val}>{fmt(b.check_in||b.pickup_date)}</div></div>}
              {(b.check_out||b.return_date) && <div><span style={s.lbl}>{b.type==='hotel'?'Check-out':'Return'}</span><div style={s.val}>{fmt(b.check_out||b.return_date)}</div></div>}
              {details.city && <div><span style={s.lbl}>City</span><div style={s.val}>{details.city}</div></div>}
              {details.country && <div><span style={s.lbl}>Country</span><div style={s.val}>{details.country}</div></div>}
              {details.room_type && <div><span style={s.lbl}>Room type</span><div style={s.val}>{details.room_type}</div></div>}
              {details.meal_plan && <div><span style={s.lbl}>Meal plan</span><div style={s.val}>{details.meal_plan}</div></div>}
              {details.occupancy && <div><span style={s.lbl}>Occupancy</span><div style={s.val}>{details.occupancy}</div></div>}
              {details.view_type && details.view_type!=='No preference' && <div><span style={s.lbl}>View</span><div style={s.val}>{details.view_type}</div></div>}
              {details.car_type && <div><span style={s.lbl}>Vehicle</span><div style={s.val}>{details.car_type}</div></div>}
              {details.rental_company && <div><span style={s.lbl}>Rental company</span><div style={s.val}>{details.rental_company || details.service_name}</div></div>}
              {details.pickup_location && <div><span style={s.lbl}>Pickup</span><div style={s.val}>{details.pickup_location}</div></div>}
              {details.return_location && <div><span style={s.lbl}>Return</span><div style={s.val}>{details.return_location}</div></div>}
              {details.from && <div><span style={s.lbl}>From</span><div style={s.val}>{details.from}</div></div>}
              {details.to && <div><span style={s.lbl}>To</span><div style={s.val}>{details.to}</div></div>}
              {details.vehicle_type && <div><span style={s.lbl}>Vehicle</span><div style={s.val}>{details.vehicle_type}</div></div>}
              {details.flight_number && <div><span style={s.lbl}>Flight no.</span><div style={s.val}>{details.flight_number}</div></div>}
              {details.airline && <div><span style={s.lbl}>Airline</span><div style={s.val}>{details.airline} {details.flight_no}</div></div>}
              {details.origin && <div><span style={s.lbl}>Route</span><div style={s.val}>{details.origin} → {details.destination}</div></div>}
              {details.cabin_class && <div><span style={s.lbl}>Class</span><div style={s.val}>{details.cabin_class}</div></div>}
              {details.pnr && <div><span style={s.lbl}>PNR</span><div style={{ ...s.val, fontFamily:'monospace', color:'#185FA5', fontWeight:700 }}>{details.pnr}</div></div>}
              {details.restaurant && <div><span style={s.lbl}>Restaurant</span><div style={s.val}>{details.restaurant}</div></div>}
              {details.meal_type && <div><span style={s.lbl}>Meal type</span><div style={s.val}>{details.meal_type}</div></div>}
              {details.site_name && <div><span style={s.lbl}>Site</span><div style={s.val}>{details.site_name}</div></div>}
              <div><span style={s.lbl}>Travelers</span><div style={s.val}>{b.num_travelers}</div></div>
              {b.supplier_confirmation && <div><span style={s.lbl}>Supplier ref.</span><div style={{ ...s.val, color:'#185FA5', fontWeight:700 }}>{b.supplier_confirmation}</div></div>}
            </div>

            {/* Travelers table */}
            <div style={s.secHead}>{b.type==='flight'?'Passengers':b.type==='hotel'?'Registered Guests':'Travelers'}</div>
            <table style={{ width:'100%', borderCollapse:'collapse', fontSize:10, marginBottom:10 }}>
              <thead>
                <tr>
                  <th style={s.th}>#</th>
                  <th style={s.th}>Full name</th>
                  <th style={s.th}>Type</th>
                  {['flight','hotel'].includes(b.type) && <th style={s.th}>Passport no.</th>}
                  {['flight','hotel'].includes(b.type) && <th style={s.th}>Date of birth</th>}
                  <th style={s.th}>Nationality</th>
                </tr>
              </thead>
              <tbody>
                {travelers.map((tr: any, i: number) => (
                  <tr key={i} style={{ background: i%2===1?'#fafafa':'#fff' }}>
                    <td style={s.td}>{i+1}</td>
                    <td style={{ ...s.td, fontWeight:600 }}>{tr.full_name}</td>
                    <td style={s.td}><span style={{ fontSize:8, fontWeight:500, padding:'1px 5px', borderRadius:8, background:tr.type==='child'?'#B5D4F4':'#E6F1FB', color:tr.type==='child'?'#042C53':'#0C447C' }}>{tr.type==='child'?`Child · ${tr.age}`:tr.is_lead?'Adult · Lead':'Adult'}</span></td>
                    {['flight','hotel'].includes(b.type) && <td style={{ ...s.td, fontFamily:'monospace' }}>{tr.passport_number||'—'}</td>}
                    {['flight','hotel'].includes(b.type) && <td style={s.td}>{tr.date_of_birth||'—'}</td>}
                    <td style={s.td}>{tr.nationality||'—'}</td>
                  </tr>
                ))}
              </tbody>
            </table>

            {/* Pricing */}
            {showPrices && (
              <div style={s.priceStrip}>
                {[['Total price',formatMoney(b.total_price, b.currency),'#1a2a3a'],['Paid',formatMoney(paidAmount, b.currency),'#0F6E56'],['Balance due',formatMoney(balanceNum, b.currency),balanceNum>0?'#854F0B':'#0F6E56'],['Status',isPaid?'PAID ✓':STATUS_LABELS[b.status],isPaid?'#0F6E56':'#854F0B']].map(([lbl,val,clr],i,arr) => (
                  <div key={lbl} style={{ flex:1, textAlign:'center', borderRight:i<arr.length-1?'0.5px solid #dde3ea':'none' }}>
                    <span style={{ fontSize:8, color:'#888', textTransform:'uppercase', display:'block', marginBottom:2 }}>{lbl}</span>
                    <span style={{ fontSize:i===3?12:16, fontWeight:700, color:clr }}>{val}</span>
                  </div>
                ))}
              </div>
            )}

            {/* Notes */}
            {b.notes && <div style={{ background:'#fffbf0', border:'0.5px solid #f5c842', borderRadius:6, padding:'7px 10px', fontSize:10, color:'#412402', marginBottom:10 }}><strong style={{ display:'block', marginBottom:3, fontSize:8, textTransform:'uppercase', letterSpacing:'.3px', color:'#1a2a3a' }}>Special requests</strong>{b.notes}</div>}

            {/* Present to supplier note */}
            {isPaid && <div style={{ background:'#E1F5EE', border:'0.5px solid #5DCAA5', borderRadius:6, padding:'7px 12px', fontSize:9, color:'#085041', textAlign:'center', marginBottom:10 }}><strong>Please present this voucher to the service provider.</strong><br/>For assistance: {company.company_name} · {company.phone} · {company.email} · {company.website}</div>}
          </div>

          {/* Footer */}
          <div style={s.footer}>
            <div style={{ fontSize:9, color:'#7899bb' }}>{company.company_name} · {company.website}</div>
            <div style={{ fontSize:9, color:'#f5c842', fontWeight:500, textAlign:'center' }}>{isPaid?vchNum:`${client.file_number} · ${bc.label}`}</div>
            <div style={{ fontSize:9, color:'#7899bb' }}>Page 1 of 1 · {new Date().toLocaleDateString('en-GB')}</div>
          </div>
        </div>
      </div>
      <style>{`
        @media print {
          /* Hide everything by default */
          body * { visibility: hidden !important; }
          /* Show only the voucher and everything inside it */
          #voucher-print-root, #voucher-print-root * { visibility: visible !important; }
          /* Pull the voucher to the top-left and let it fill the page */
          #voucher-print-root {
            position: absolute !important;
            left: 0 !important;
            top: 0 !important;
            width: 100% !important;
            background: #fff !important;
            padding: 0 !important;
            overflow: visible !important;
            direction: ltr !important; text-align: left !important;
          }
          /* Hide the action buttons when printing */
          .no-print { display: none !important; }
          @page { margin: 12mm; }
        }
      `}</style>
    </div>
  )
}

/* ─── BOOKING ROW ─────────────────────────────────────────────────────────── */
function BookingRow({ booking: b, client, onStatusChange, onVoucher, onFinanceChange, onEdit, onDuplicate }: { booking: any; client?: any; onStatusChange: (s: string) => void; onVoucher: () => void; onFinanceChange?: () => void; onEdit?: () => void; onDuplicate?: () => void }) {
  const [showFinance, setShowFinance] = useState(false)
  const stepIdx = STATUS_STEPS.indexOf(b.status)
  const bc = BOOKING_TYPES.find(bt => bt.key === b.type)
  const isVoucherStage = ['paid', 'voucher_sent', 'completed'].includes(b.status)

  function sendWhatsApp() {
    if (!client?.phone) return
    const company = getCachedSettings().company_name
    const msg = isVoucherStage
      ? voucherMessage({ clientName: client.full_name, serviceName: b.service_name, fileNumber: client.file_number, companyName: company })
      : quoteMessage({ clientName: client.full_name, serviceName: b.service_name, totalPrice: Number(b.total_price) || undefined, currency: b.currency, fileNumber: client.file_number, companyName: company })
    openWhatsApp(client.phone, msg)
  }

  return (
    <div style={{ padding: '14px 16px', borderBottom: '0.5px solid #f0f0f0' }}>
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 10 }}>
        <div>
          <div style={{ display:'flex', alignItems:'center', gap:6, marginBottom:2 }}>
            {bc && <span style={{ background:bc.bg, color:bc.color, fontSize:9, fontWeight:600, padding:'1px 7px', borderRadius:10 }}>{bc.label}</span>}
          </div>
          <div style={{ fontSize: 14, fontWeight: 600 }}>{b.service_name}</div>
          <div style={{ fontSize: 11, color: '#888', marginTop: 2 }}>
            {b.check_in || b.pickup_date || b.date}
            {(b.check_out || b.return_date) ? ` → ${b.check_out || b.return_date}` : ''}
            {' · '}{b.num_travelers} travelers
          </div>
          {b.supplier_confirmation && <div style={{ fontSize: 10, color: '#0F6E56', marginTop: 2 }}>Ref: {b.supplier_confirmation}</div>}
        </div>
        <div style={{ textAlign: 'right' }}>
          <div style={{ fontSize: 18, fontWeight: 700 }}>{formatMoney(b.total_price, b.currency)}</div>
          <div style={{ fontSize: 10, color: '#854F0B' }}>{b.currency || 'USD'}</div>
        </div>
      </div>
      {/* Status bar */}
      <div style={{ display: 'flex', alignItems: 'center', marginBottom: 10 }}>
        {STATUS_STEPS.map((s, i) => (
          <React.Fragment key={s}>
            <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', flex: 1 }}>
              <div style={{ width: 22, height: 22, borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 10, fontWeight: 600, border: `1.5px solid ${i <= stepIdx ? '#1D9E75' : '#ddd'}`, background: i < stepIdx ? '#1D9E75' : i === stepIdx ? '#E1F5EE' : '#fff', color: i < stepIdx ? '#fff' : i === stepIdx ? '#0F6E56' : '#aaa' }}>
                {i < stepIdx ? '✓' : i + 1}
              </div>
              <div style={{ fontSize: 8, color: i <= stepIdx ? '#0F6E56' : '#aaa', marginTop: 2, textAlign: 'center', whiteSpace: 'nowrap' }}>{STATUS_LABELS[s]}</div>
            </div>
            {i < STATUS_STEPS.length - 1 && <div style={{ flex: 1, height: 1.5, background: i < stepIdx ? '#1D9E75' : '#eee', marginBottom: 14 }} />}
          </React.Fragment>
        ))}
      </div>
      {/* Actions */}
      <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap' }}>
        {b.status === 'inquiry'      && <Abtn label="Confirm Quote"   color="#185FA5" bg="#E6F1FB" onClick={() => onStatusChange('quoted')} />}
        {b.status === 'quoted'       && <Abtn label="Confirm Booking" color="#0F6E56" bg="#E1F5EE" onClick={() => onStatusChange('confirmed')} />}
        {b.status === 'confirmed'    && <Abtn label="Mark as Paid"    color="#3B6D11" bg="#EAF3DE" onClick={() => onStatusChange('paid')} />}
        {b.status === 'paid'         && <Abtn label="Send Voucher"    color="#534AB7" bg="#EEEDFE" onClick={() => onStatusChange('voucher_sent')} />}
        {b.status === 'voucher_sent' && <Abtn label="Complete"        color="#0F6E56" bg="#E1F5EE" onClick={() => onStatusChange('completed')} />}
        {!['completed','cancelled'].includes(b.status) && <Abtn label="Cancel" color="#A32D2D" bg="#FCEBEB" onClick={() => onStatusChange('cancelled')} />}
        <Abtn label="📄 View / Print" color="#1a2a3a" bg="#f0f4f8" onClick={onVoucher} />
        {client?.phone && (
          <Abtn label={`💬 Send ${isVoucherStage ? 'Voucher' : 'Quote'} on WhatsApp`} color="#0F6E56" bg="#E1F5EE" onClick={sendWhatsApp} />
        )}
        <Abtn label="✏️ Edit" color="#854F0B" bg="#FAEEDA" onClick={() => onEdit?.()} />
        <Abtn label="⧉ Duplicate" color="#534AB7" bg="#EEEDFE" onClick={() => onDuplicate?.()} />
        <Abtn label={showFinance ? '💰 Hide Financials' : '💰 Financials'} color="#0F6E56" bg="#E1F5EE" onClick={() => setShowFinance(s => !s)} />
      </div>
      {showFinance && (
        <div style={{ marginTop: 12 }}>
          <FinancialPanel booking={b} onChange={onFinanceChange} />
        </div>
      )}
    </div>
  )
}

function Abtn({ label, color, bg, onClick }: { label: string; color: string; bg: string; onClick: () => void }) {
  return <button onClick={onClick} style={{ padding: '5px 12px', background: bg, color, border: `0.5px solid ${color}44`, borderRadius: 8, cursor: 'pointer', fontSize: 11, fontWeight: 500 }}>{label}</button>
}

/* ─── BOOKING FORM ──────────────────────────────────────────────────────── */
function BookingForm({ type, clientId, fileNumber, travelers, onSave, onCancel, existing }: any) {
  const inp: React.CSSProperties = { width: '100%', padding: '6px 8px', border: '0.5px solid #d0d0d0', borderRadius: 6, fontSize: 12, outline: 'none', background: '#fafafa', color: '#1a1a1a' }
  const lbl: React.CSSProperties = { fontSize: 10, color: '#555', fontWeight: 500, display: 'block', marginBottom: 3 }
  const pre: React.CSSProperties = { ...inp, background: '#E1F5EE', borderColor: '#5DCAA5', color: '#085041' }
  const g3: React.CSSProperties = { display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: 8, marginBottom: 8 }
  const g2: React.CSSProperties = { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8, marginBottom: 8 }

  const lead = travelers.find((t: any) => t.is_lead) || travelers[0]
  const adults = travelers.filter((t: any) => t.type !== 'child')
  const children = travelers.filter((t: any) => t.type === 'child')

  const [f, setF] = useState<any>(existing?.details ? {
    // Start from existing details, but ensure top-level edits are reflected
    ...existing.details,
    service_name: existing.service_name ?? existing.details.service_name ?? '',
    check_in: existing.check_in ?? existing.details.check_in ?? '',
    check_out: existing.check_out ?? existing.details.check_out ?? '',
    pickup_date: existing.pickup_date ?? existing.details.pickup_date ?? '',
    return_date: existing.return_date ?? existing.details.return_date ?? '',
    num_travelers: existing.num_travelers ?? existing.details.num_travelers ?? travelers.length,
    total_price: existing.total_price != null ? String(existing.total_price) : (existing.details.total_price ?? ''),
    deposit_paid: existing.deposit_paid != null ? String(existing.deposit_paid) : (existing.details.deposit_paid ?? '0'),
    supplier_confirmation: existing.supplier_confirmation ?? existing.details.supplier_confirmation ?? '',
    notes: existing.notes ?? existing.details.notes ?? '',
  } : {
    service_name:'', check_in:'', check_out:'', pickup_date:'', return_date:'',
    num_travelers: travelers.length, total_price:'', deposit_paid:'0',
    supplier_confirmation:'', notes:'',
    // Hotel
    city:'', country:'', room_type:'Deluxe Double', meal_plan:'RO – Room only',
    nights:'', view_type:'No preference', num_rooms:'1', extra_bed:'None',
    payment_supplier:'Credit card', cancellation_policy:'Free cancellation', occupancy:'2 Adults',
    // Car
    car_type:'Compact', rental_company:'', pickup_location:'', return_location:'', insurance:'Full', days:'',
    // Transfer
    from:'', to:'', flight_number:'', vehicle_type:'Minibus', transfer_time:'',
    // Day trip
    meeting_point:'', meeting_time:'', guide:'',
    // Entrance
    site_name:'', price_adult:'', price_child:'',
    // Meals
    restaurant:'', meal_type:'Dinner', dietary:'',
    // Flight
    airline:'', flight_no:'', origin:'', destination:'', departure_time:'', arrival_time:'', cabin_class:'Economy', baggage:'', pnr:'',
    // VIP
    vip_direction:'Arrival', vip_service:'Silver Arrival', vip_price:'350',
  })
  const s = (k: string, v: any) => setF((p: any) => ({ ...p, [k]: v }))

  const autoCalc = () => {
    const ap = parseFloat(f.price_adult)||0
    const cp = parseFloat(f.price_child)||0
    const total = (ap*adults.length)+(cp*children.length)
    if(total>0) s('total_price', String(total))
  }

  const GuestBar = ({ color, text }: { color: string; text: string }) => (
    <div style={{ background: color==='green'?'#E1F5EE':color==='blue'?'#E6F1FB':color==='purple'?'#EEEDFE':color==='pink'?'#FBEAF0':color==='gold'?'#FFF8E6':'#B5D4F4', border: `0.5px solid ${color==='green'?'#5DCAA5':color==='blue'?'#85B7EB':color==='purple'?'#AFA9EC':color==='pink'?'#ED93B1':color==='gold'?'#f5c842':'#6AAAE0'}`, borderRadius: 8, padding: '6px 10px', marginBottom: 8, fontSize: 10, color: color==='green'?'#085041':color==='blue'?'#0C447C':color==='purple'?'#3C3489':color==='pink'?'#6B2340':color==='gold'?'#412402':'#0C447C' }}>
      <strong>🔒 Auto-transferred: </strong>{text}
    </div>
  )

  return (
    <div style={{ padding: '14px 16px', background: '#f8fafc', borderBottom: '0.5px solid #e5e5e5' }}>
      <div style={{ fontSize: 13, fontWeight: 600, marginBottom: 10, color: '#1a2a3a' }}>
        New Booking — {BOOKING_TYPES.find(b => b.key === type)?.label}
      </div>

      {/* HOTEL */}
      {type === 'hotel' && <>
        <div style={g3}>
          <div><label style={lbl}>Hotel Name</label><input style={inp} value={f.service_name} onChange={e => s('service_name', e.target.value)} placeholder="Hotel name" /></div>
          <div><label style={lbl}>City / Destination</label><input style={inp} value={f.city} onChange={e => s('city', e.target.value)} placeholder="Jerusalem, Cairo..." /></div>
          <div><label style={lbl}>Country</label><input style={inp} value={f.country} onChange={e => s('country', e.target.value)} placeholder="Israel, Egypt..." /></div>
        </div>
        <div style={g3}>
          <div><label style={lbl}>Check-in</label><input type="date" style={inp} value={f.check_in} onChange={e => { s('check_in', e.target.value); const d=Math.round((new Date(f.check_out).getTime()-new Date(e.target.value).getTime())/86400000); if(d>0) s('nights',String(d)) }} /></div>
          <div><label style={lbl}>Check-out</label><input type="date" style={inp} value={f.check_out} onChange={e => { s('check_out', e.target.value); const d=Math.round((new Date(e.target.value).getTime()-new Date(f.check_in).getTime())/86400000); if(d>0) s('nights',String(d)) }} /></div>
          <div><label style={lbl}>Nights</label><input style={{ ...inp, background: '#E6F1FB', borderColor: '#85B7EB', color: '#0C447C', fontWeight: 500 }} value={f.nights ? `${f.nights} nights` : ''} readOnly /></div>
        </div>
        <div style={{ marginBottom: 8 }}>
          <label style={lbl}>Room Occupancy</label>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3,1fr)', gap: 5 }}>
            {['1 Adult','2 Adults','1 Adult + 1 Child','2 Adults + 1 Child','2 Adults + 2 Children','Custom'].map(opt => (
              <button key={opt} onClick={() => s('occupancy', opt)} style={{ border: f.occupancy===opt ? '2px solid #185FA5' : '0.5px solid #ddd', borderRadius: 8, padding: '6px 4px', cursor: 'pointer', background: f.occupancy===opt ? '#E6F1FB' : '#fff', fontSize: 10, color: f.occupancy===opt ? '#0C447C' : '#555', fontWeight: f.occupancy===opt ? 600 : 400 }}>{opt}</button>
            ))}
          </div>
        </div>
        <div style={g3}>
          <div><label style={lbl}>Room Type</label><select style={inp} value={f.room_type} onChange={e => s('room_type',e.target.value)}>{['Standard Double','Deluxe Double','Twin','Triple','Suite','Junior Suite','Family Room'].map(r=><option key={r}>{r}</option>)}</select></div>
          <div><label style={lbl}>View</label><select style={inp} value={f.view_type} onChange={e => s('view_type',e.target.value)}>{['No preference','Sea view','Garden view','City view','Pool view','Mountain view'].map(v=><option key={v}>{v}</option>)}</select></div>
          <div><label style={lbl}>No. of Rooms</label><input type="number" min="1" style={inp} value={f.num_rooms} onChange={e => s('num_rooms',e.target.value)} /></div>
        </div>
        <div style={g3}>
          <div><label style={lbl}>Meal Plan</label><select style={inp} value={f.meal_plan} onChange={e => s('meal_plan',e.target.value)}>{['RO – Room only','BB – Bed & Breakfast','HB – Half Board','FB – Full Board','AI – All Inclusive'].map(m=><option key={m}>{m}</option>)}</select></div>
          <div><label style={lbl}>Extra Bed / Crib</label><select style={inp} value={f.extra_bed} onChange={e => s('extra_bed',e.target.value)}>{['None','Extra bed','Baby crib','Extra bed + crib'].map(e=><option key={e}>{e}</option>)}</select></div>
          <div><label style={lbl}>Payment to Supplier</label><select style={inp} value={f.payment_supplier} onChange={e => s('payment_supplier',e.target.value)}>{['Credit card','Bank transfer','Cash on arrival','Voucher','Net rate'].map(p=><option key={p}>{p}</option>)}</select></div>
        </div>
        <GuestBar color="green" text={travelers.map((t:any,i:number)=>`${i+1}. ${t.full_name} · ${t.type==='child'?`Child age ${t.age}`:'Adult'}${t.passport_number?` · ${t.passport_number}`:''}`).join(' | ')} />
      </>}

      {/* CAR RENTAL — Europcar Israel */}
      {type === 'car_rental' && <>
        <GuestBar color="green" text={`Lead driver: ${lead?.full_name} · ${lead?.passport_number||''} · ${lead?.nationality||''}`} />
        {/* Dates + Location */}
        <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr 1fr 1fr', gap:8, marginBottom:8 }}>
          <div><label style={lbl}>Pickup Date</label><input type="date" style={inp} value={f.pickup_date} onChange={e => { s('pickup_date',e.target.value); const d=Math.round((new Date(f.return_date).getTime()-new Date(e.target.value).getTime())/86400000); if(d>0) s('days',String(d)) }} /></div>
          <div><label style={lbl}>Return Date</label><input type="date" style={inp} value={f.return_date} onChange={e => { s('return_date',e.target.value); const d=Math.round((new Date(e.target.value).getTime()-new Date(f.pickup_date).getTime())/86400000); if(d>0) s('days',String(d)) }} /></div>
          <div><label style={lbl}>Pickup Location</label><input style={inp} value={f.pickup_location} onChange={e => s('pickup_location',e.target.value)} placeholder="Airport, Hotel..." /></div>
          <div><label style={lbl}>Return Location</label><select style={inp} value={f.return_location} onChange={e => s('return_location',e.target.value)}><option>Same as pickup</option><option>Different location</option></select></div>
        </div>
        {f.days && <div style={{ marginBottom:8 }}><span style={{ background:'#E1F5EE', color:'#085041', fontSize:11, fontWeight:600, padding:'3px 10px', borderRadius:20 }}>📅 {f.days} days</span></div>}

        {/* Vehicle Type Tabs */}
        <div style={{ marginBottom:8 }}>
          <label style={lbl}>Vehicle Type — Europcar Israel</label>
          <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:5, marginBottom:8 }}>
            {[
              { key:'sedan', label:'Sedans & Luxury' },
              { key:'suv',   label:'SUV / STW' },
              { key:'van',   label:'Vans 7–9 seats' },
              { key:'pickup',label:'Pickup / Cab' },
            ].map(t => (
              <button key={t.key} onClick={() => { s('car_type_group', t.key); s('car_type',''); s('service_name','Europcar Israel') }}
                style={{ border: f.car_type_group===t.key ? '2px solid #0F6E56' : '0.5px solid #ddd', borderRadius:8, padding:'6px 4px', cursor:'pointer', background: f.car_type_group===t.key ? '#E1F5EE' : '#fff', fontSize:10, color: f.car_type_group===t.key ? '#085041' : '#666', fontWeight: f.car_type_group===t.key ? 600 : 400 }}>
                {t.label}
              </button>
            ))}
          </div>

          {/* Sedans */}
          {f.car_type_group === 'sedan' && (
            <div>
              {[
                { cat:'Mini (4 seats)', cars:[{name:'Suzuki Alto Manual',grp:'B',code:'MBMR'},{name:'Toyota Aygo',grp:'Q',code:'MBAR'}] },
                { cat:'Economy (4 seats)', cars:[{name:'Kia Picanto',grp:'C',code:'EBAR'},{name:'Hyundai i20',grp:'D',code:'ECAR'}] },
                { cat:'Economy Elite (5 seats)', cars:[{name:'Ford Fiesta',grp:'E',code:'EDAR'},{name:'Hyundai Accent',grp:'F',code:'EZAR'}] },
                { cat:'Compact → Standard → Luxury (5 seats)', cars:[{name:'Mazda 3',grp:'I',code:'CCAR'},{name:'Mazda 6',grp:'M',code:'SDAR'},{name:'Skoda Superb',grp:'R',code:'SCAR'},{name:'Nissan Maxima',grp:'P',code:'LDAR'},{name:'Audi A6',grp:'W',code:'LCBR'}] },
              ].map(({ cat, cars }) => (
                <div key={cat} style={{ marginBottom:6 }}>
                  <div style={{ fontSize:9, fontWeight:500, color:'#888', textTransform:'uppercase', letterSpacing:'.3px', borderBottom:'0.5px solid #eee', paddingBottom:3, marginBottom:4 }}>{cat}</div>
                  <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:4 }}>
                    {cars.map(c => (
                      <button key={c.name} onClick={() => { s('car_type',c.name); s('car_group',c.grp); s('service_name',`Europcar — ${c.name}`) }}
                        style={{ border: f.car_type===c.name ? '2px solid #0F6E56' : '0.5px solid #ddd', borderRadius:6, padding:'5px 7px', cursor:'pointer', background: f.car_type===c.name ? '#E1F5EE' : '#fff', textAlign:'left', position:'relative' }}>
                        <span style={{ position:'absolute', top:3, right:4, fontSize:8, fontWeight:600, background: f.car_type===c.name?'#0F6E56':'#E1F5EE', color: f.car_type===c.name?'#fff':'#085041', padding:'0 4px', borderRadius:6 }}>{c.grp}</span>
                        <div style={{ fontSize:10, fontWeight:600, color: f.car_type===c.name?'#085041':'#1a1a1a' }}>{c.name}</div>
                        <div style={{ fontSize:8, color:'#888', marginTop:1 }}>{c.code}</div>
                      </button>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          )}

          {/* SUVs */}
          {f.car_type_group === 'suv' && (
            <div>
              {[
                { cat:'Compact SW / SUV (5 seats)', cars:[{name:'Ford Focus SW',grp:'IW',code:'CWAR'},{name:'Mitsubishi ASX',grp:'H',code:'CFAR'}] },
                { cat:'Standard → Luxury SUV (5 seats)', cars:[{name:'Hyundai Tucson Aut.',grp:'J',code:'SFBR'},{name:'Ford Edge Aut.',grp:'O',code:'LFBR'}] },
              ].map(({ cat, cars }) => (
                <div key={cat} style={{ marginBottom:6 }}>
                  <div style={{ fontSize:9, fontWeight:500, color:'#888', textTransform:'uppercase', letterSpacing:'.3px', borderBottom:'0.5px solid #eee', paddingBottom:3, marginBottom:4 }}>{cat}</div>
                  <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:4 }}>
                    {cars.map(c => (
                      <button key={c.name} onClick={() => { s('car_type',c.name); s('car_group',c.grp); s('service_name',`Europcar — ${c.name}`) }}
                        style={{ border: f.car_type===c.name ? '2px solid #0F6E56' : '0.5px solid #ddd', borderRadius:6, padding:'5px 7px', cursor:'pointer', background: f.car_type===c.name ? '#E1F5EE' : '#fff', textAlign:'left', position:'relative' }}>
                        <span style={{ position:'absolute', top:3, right:4, fontSize:8, fontWeight:600, background: f.car_type===c.name?'#0F6E56':'#E1F5EE', color: f.car_type===c.name?'#fff':'#085041', padding:'0 4px', borderRadius:6 }}>{c.grp}</span>
                        <div style={{ fontSize:10, fontWeight:600, color: f.car_type===c.name?'#085041':'#1a1a1a' }}>{c.name}</div>
                        <div style={{ fontSize:8, color:'#888', marginTop:1 }}>{c.code}</div>
                      </button>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          )}

          {/* Vans */}
          {f.car_type_group === 'van' && (
            <div style={{ marginBottom:6 }}>
              <div style={{ fontSize:9, fontWeight:500, color:'#888', textTransform:'uppercase', letterSpacing:'.3px', borderBottom:'0.5px solid #eee', paddingBottom:3, marginBottom:4 }}>Vans 7–9 seats</div>
              <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:4 }}>
                {[{name:'Opel Zafira Aut.',grp:'U',code:'IVAR',seats:7},{name:'Mitsubishi Outlander',grp:'V',code:'SVAR',seats:7},{name:'Kia Carnival',grp:'V8',code:'FVAR',seats:8},{name:'Renault Traffic',grp:'Y',code:'FVMR',seats:9},{name:'Toyota Proace',grp:'Z',code:'LVAR',seats:9}].map(c => (
                  <button key={c.name} onClick={() => { s('car_type',c.name); s('car_group',c.grp); s('service_name',`Europcar — ${c.name}`) }}
                    style={{ border: f.car_type===c.name ? '2px solid #0F6E56' : '0.5px solid #ddd', borderRadius:6, padding:'5px 7px', cursor:'pointer', background: f.car_type===c.name ? '#E1F5EE' : '#fff', textAlign:'left', position:'relative' }}>
                    <span style={{ position:'absolute', top:3, right:4, fontSize:8, fontWeight:600, background: f.car_type===c.name?'#0F6E56':'#E1F5EE', color: f.car_type===c.name?'#fff':'#085041', padding:'0 4px', borderRadius:6 }}>{c.grp}</span>
                    <div style={{ fontSize:10, fontWeight:600, color: f.car_type===c.name?'#085041':'#1a1a1a' }}>{c.name}</div>
                    <div style={{ fontSize:8, color:'#888', marginTop:1 }}>{c.seats} seats · {c.code}</div>
                  </button>
                ))}
              </div>
            </div>
          )}

          {/* Pickup */}
          {f.car_type_group === 'pickup' && (
            <div style={{ marginBottom:6 }}>
              <div style={{ fontSize:9, fontWeight:500, color:'#888', textTransform:'uppercase', letterSpacing:'.3px', borderBottom:'0.5px solid #eee', paddingBottom:3, marginBottom:4 }}>Pickup / Cab</div>
              <div style={{ display:'grid', gridTemplateColumns:'repeat(4,1fr)', gap:4 }}>
                {[{name:'Citroen Berlingo',grp:'T',code:'CPAR',seats:5}].map(c => (
                  <button key={c.name} onClick={() => { s('car_type',c.name); s('car_group',c.grp); s('service_name',`Europcar — ${c.name}`) }}
                    style={{ border: f.car_type===c.name ? '2px solid #0F6E56' : '0.5px solid #ddd', borderRadius:6, padding:'5px 7px', cursor:'pointer', background: f.car_type===c.name ? '#E1F5EE' : '#fff', textAlign:'left', position:'relative' }}>
                    <span style={{ position:'absolute', top:3, right:4, fontSize:8, fontWeight:600, background: f.car_type===c.name?'#0F6E56':'#E1F5EE', color: f.car_type===c.name?'#fff':'#085041', padding:'0 4px', borderRadius:6 }}>{c.grp}</span>
                    <div style={{ fontSize:10, fontWeight:600, color: f.car_type===c.name?'#085041':'#1a1a1a' }}>{c.name}</div>
                    <div style={{ fontSize:8, color:'#888', marginTop:1 }}>{c.seats} seats · {c.code}</div>
                  </button>
                ))}
              </div>
            </div>
          )}

          {/* Selected vehicle confirmation */}
          {f.car_type && <div style={{ background:'#E1F5EE', border:'0.5px solid #5DCAA5', borderRadius:6, padding:'5px 10px', fontSize:10, color:'#085041', marginTop:4 }}>✅ Selected: <strong>{f.car_type}</strong> or similar · Group {f.car_group}</div>}
        </div>

        {/* Insurance + Extras */}
        <div style={g2}>
          <div>
            <label style={lbl}>Coverage</label>
            <select style={inp} value={f.insurance} onChange={e => s('insurance',e.target.value)}>
              <option>Inclusive — CDW + THW</option>
              <option>Super CDW upgrade</option>
              <option>Full super package</option>
            </select>
          </div>
          <div>
            <label style={lbl}>Mileage</label>
            <select style={inp}>
              <option>250 km/day (1–2 days)</option>
              <option>Unlimited (3+ days)</option>
              <option>Weekly unlimited</option>
            </select>
          </div>
        </div>
        <div style={g2}>
          <div><label style={lbl}>Payment to Supplier</label><select style={inp} value={f.payment_supplier} onChange={e => s('payment_supplier',e.target.value)}>{['Credit card','Bank transfer','Cash','Voucher'].map(p=><option key={p}>{p}</option>)}</select></div>
          <div><label style={lbl}>Cancellation Policy</label><select style={inp} value={f.cancellation_policy} onChange={e => s('cancellation_policy',e.target.value)}>{['Free cancellation','Non-refundable','48h free cancel','72h free cancel'].map(c=><option key={c}>{c}</option>)}</select></div>
        </div>
      </>}

      {/* TRANSFER */}
      {type === 'transfer' && <>
        <div style={{ marginBottom: 8 }}>
          <label style={lbl}>Service Type</label>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 6 }}>
            {['Point to Point Transfer','VIP Airport Services (Fast Track)'].map(opt => (
              <button key={opt} onClick={() => s('transfer_type', opt)} style={{ border: f.transfer_type===opt ? '2px solid #854F0B' : '0.5px solid #ddd', borderRadius: 8, padding: '7px 10px', cursor: 'pointer', background: f.transfer_type===opt ? '#FAEEDA' : '#fff', fontSize: 11, color: f.transfer_type===opt ? '#633806' : '#555', fontWeight: f.transfer_type===opt ? 600 : 400, textAlign: 'left' }}>{opt}</button>
            ))}
          </div>
        </div>
        <GuestBar color="blue" text={`${lead?.full_name} · ${travelers.length} travelers`} />
        <div style={g3}>
          <div><label style={lbl}>From</label><input style={inp} value={f.from} onChange={e => { s('from',e.target.value); s('service_name',`Transfer: ${e.target.value} → ${f.to}`) }} placeholder="Airport, Hotel..." /></div>
          <div><label style={lbl}>To</label><input style={inp} value={f.to} onChange={e => { s('to',e.target.value); s('service_name',`Transfer: ${f.from} → ${e.target.value}`) }} placeholder="Hotel, City..." /></div>
          <div><label style={lbl}>Vehicle Type</label><select style={inp} value={f.vehicle_type} onChange={e => s('vehicle_type',e.target.value)}>{['Sedan','SUV','Minibus','Van','Bus','Luxury sedan','Sprinter'].map(v=><option key={v}>{v}</option>)}</select></div>
        </div>
        <div style={g3}>
          <div><label style={lbl}>Date</label><input type="date" style={inp} value={f.pickup_date} onChange={e => s('pickup_date',e.target.value)} /></div>
          <div><label style={lbl}>Time</label><input type="time" style={inp} value={f.transfer_time} onChange={e => s('transfer_time',e.target.value)} /></div>
          <div><label style={lbl}>Flight No.</label><input style={inp} value={f.flight_number} onChange={e => s('flight_number',e.target.value)} placeholder="LY001..." /></div>
        </div>
        <div style={g2}>
          <div><label style={lbl}>No. of Passengers</label><input style={pre} value={travelers.length} readOnly /></div>
          <div><label style={lbl}>Payment to Supplier</label><select style={inp} value={f.payment_supplier} onChange={e => s('payment_supplier',e.target.value)}>{['Credit card','Cash','Bank transfer','Voucher'].map(p=><option key={p}>{p}</option>)}</select></div>
        </div>
      </>}

      {/* DAY TRIP */}
      {type === 'day_trip' && <>
        <GuestBar color="green" text={travelers.map((t:any,i:number)=>`${i+1}. ${t.full_name}${t.type==='child'?` (Child age ${t.age})`:''}`).join(' | ')} />
        <div style={g3}>
          <div><label style={lbl}>Trip Name / Destination</label><input style={inp} value={f.service_name} onChange={e => s('service_name',e.target.value)} placeholder="Dead Sea, Petra, Masada..." /></div>
          <div><label style={lbl}>Date</label><input type="date" style={inp} value={f.pickup_date} onChange={e => s('pickup_date',e.target.value)} /></div>
          <div><label style={lbl}>Guide Name / Company</label><input style={inp} value={f.guide} onChange={e => s('guide',e.target.value)} /></div>
        </div>
        <div style={g3}>
          <div><label style={lbl}>Meeting Point</label><input style={inp} value={f.meeting_point} onChange={e => s('meeting_point',e.target.value)} placeholder="Hotel lobby, Square..." /></div>
          <div><label style={lbl}>Meeting Time</label><input type="time" style={inp} value={f.meeting_time} onChange={e => s('meeting_time',e.target.value)} /></div>
          <div><label style={lbl}>Payment to Supplier</label><select style={inp} value={f.payment_supplier} onChange={e => s('payment_supplier',e.target.value)}>{['Credit card','Cash','Bank transfer','Voucher'].map(p=><option key={p}>{p}</option>)}</select></div>
        </div>
      </>}

      {/* ENTRANCE */}
      {type === 'entrance' && <>
        <GuestBar color="purple" text={`${adults.length} Adults · ${children.length} Children${children.length>0?` (Ages: ${children.map((c:any)=>c.age).join(', ')})`:''}  · Nationality: ${lead?.nationality||''}`} />
        <div style={g3}>
          <div><label style={lbl}>Site / Attraction</label><input style={inp} value={f.service_name} onChange={e => s('service_name',e.target.value)} placeholder="Masada, Petra, Louvre..." /></div>
          <div><label style={lbl}>Date</label><input type="date" style={inp} value={f.pickup_date} onChange={e => s('pickup_date',e.target.value)} /></div>
          <div><label style={lbl}>Nationality</label><input style={pre} value={lead?.nationality||''} readOnly /></div>
        </div>
        <div style={g3}>
          <div><label style={lbl}>Adults</label><input style={pre} value={adults.length} readOnly /></div>
          <div><label style={lbl}>Children</label><input style={pre} value={children.length} readOnly /></div>
          <div><label style={lbl}>Children Ages</label><input style={pre} value={children.map((c:any)=>c.age).join(', ')||'—'} readOnly /></div>
        </div>
        <div style={g3}>
          <div><label style={lbl}>Adult Price ($)</label><input type="number" style={inp} value={f.price_adult} onChange={e => { s('price_adult',e.target.value); setTimeout(autoCalc,0) }} /></div>
          <div><label style={lbl}>Child Price ($)</label><input type="number" style={inp} value={f.price_child} onChange={e => { s('price_child',e.target.value); setTimeout(autoCalc,0) }} /></div>
          <div><label style={lbl}>Ticket Type</label><select style={inp}>{['General admission','Guided tour','Skip the line','VIP'].map(t=><option key={t}>{t}</option>)}</select></div>
        </div>
      </>}

      {/* MEALS */}
      {type === 'meals' && <>
        <GuestBar color="pink" text={travelers.map((t:any,i:number)=>`${i+1}. ${t.full_name} (${t.type==='child'?'Child':'Adult'})`).join(' | ')} />
        <div style={g3}>
          <div><label style={lbl}>Restaurant Name</label><input style={inp} value={f.service_name} onChange={e => s('service_name',e.target.value)} /></div>
          <div><label style={lbl}>Date</label><input type="date" style={inp} value={f.pickup_date} onChange={e => s('pickup_date',e.target.value)} /></div>
          <div><label style={lbl}>Meal Type</label><select style={inp} value={f.meal_type} onChange={e => s('meal_type',e.target.value)}>{['Breakfast','Brunch','Lunch','Dinner','Gala dinner'].map(m=><option key={m}>{m}</option>)}</select></div>
        </div>
        <div style={g3}>
          <div><label style={lbl}>No. of Diners</label><input style={pre} value={travelers.length} readOnly /></div>
          <div><label style={lbl}>Dietary Requirements</label><input style={inp} value={f.dietary} onChange={e => s('dietary',e.target.value)} placeholder="Vegetarian, Halal, Kosher..." /></div>
          <div><label style={lbl}>Payment to Supplier</label><select style={inp} value={f.payment_supplier} onChange={e => s('payment_supplier',e.target.value)}>{['Credit card','Cash','Voucher','Bank transfer'].map(p=><option key={p}>{p}</option>)}</select></div>
        </div>
      </>}

      {/* FLIGHT */}
      {type === 'flight' && <>
        <GuestBar color="flight" text={travelers.map((t:any,i:number)=>`${i+1}. ${t.full_name}${t.passport_number?` · ${t.passport_number}`:''}${t.date_of_birth?` · ${t.date_of_birth}`:''}${t.nationality?` · ${t.nationality}`:''}`).join(' | ')} />
        <div style={g3}>
          <div><label style={lbl}>Airline</label><input style={inp} value={f.airline} onChange={e => { s('airline',e.target.value); s('service_name',`${e.target.value} ${f.flight_no}`) }} placeholder="El Al, Emirates..." /></div>
          <div><label style={lbl}>Flight No.</label><input style={inp} value={f.flight_no} onChange={e => { s('flight_no',e.target.value); s('service_name',`${f.airline} ${e.target.value}`) }} placeholder="LY001" /></div>
          <div><label style={lbl}>PNR / Booking ref.</label><input style={inp} value={f.pnr} onChange={e => { s('pnr',e.target.value); s('supplier_confirmation',e.target.value) }} /></div>
        </div>
        <div style={g3}>
          <div><label style={lbl}>Origin (IATA)</label><input style={{ ...inp, fontWeight:600, letterSpacing:2, textTransform:'uppercase' }} maxLength={3} value={f.origin} onChange={e => s('origin',e.target.value.toUpperCase())} placeholder="TLV" /></div>
          <div><label style={lbl}>Destination (IATA)</label><input style={{ ...inp, fontWeight:600, letterSpacing:2, textTransform:'uppercase' }} maxLength={3} value={f.destination} onChange={e => s('destination',e.target.value.toUpperCase())} placeholder="JFK" /></div>
          <div><label style={lbl}>Cabin Class</label><select style={inp} value={f.cabin_class} onChange={e => s('cabin_class',e.target.value)}>{['Economy','Premium Economy','Business','First'].map(c=><option key={c}>{c}</option>)}</select></div>
        </div>
        <div style={g3}>
          <div><label style={lbl}>Departure</label><input type="datetime-local" style={inp} value={f.departure_time} onChange={e => { s('departure_time',e.target.value); s('pickup_date',e.target.value.split('T')[0]) }} /></div>
          <div><label style={lbl}>Arrival</label><input type="datetime-local" style={inp} value={f.arrival_time} onChange={e => s('arrival_time',e.target.value)} /></div>
          <div><label style={lbl}>Baggage</label><input style={inp} value={f.baggage} onChange={e => s('baggage',e.target.value)} placeholder="20kg, 1 piece..." /></div>
        </div>
      </>}

      {/* VIP */}
      {type === 'vip' && <>
        <GuestBar color="gold" text={`${travelers.map((t:any)=>t.full_name).join(' · ')} · ${travelers.length} passengers`} />
        <div style={{ marginBottom: 8 }}>
          <label style={lbl}>Direction</label>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 6, marginBottom: 8 }}>
            {['Arrival','Departure'].map(dir => (
              <button key={dir} onClick={() => s('vip_direction',dir)} style={{ border: f.vip_direction===dir ? '2px solid #B8860B' : '0.5px solid #ddd', borderRadius: 8, padding: '7px', cursor: 'pointer', background: f.vip_direction===dir ? '#FFF8E6' : '#fff', fontSize: 11, color: f.vip_direction===dir ? '#412402' : '#555', fontWeight: f.vip_direction===dir ? 600 : 400 }}>✈ {dir}</button>
            ))}
          </div>
          <label style={lbl}>Service Package</label>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 6 }}>
            {(f.vip_direction==='Arrival' ? [
              { name:'Silver Arrival', price:'350', desc:'Meet at aircraft · Passport · Baggage · Escort' },
              { name:'Platinum Arrival (Fattal)', price:'720', desc:'Private terminal · Lounge · Food & drinks' },
            ] : [
              { name:'Bronze Departure', price:'310', desc:'T3 Gate G1 · VIP security · Check-in & passport' },
              { name:'Silver Departure', price:'350', desc:'Bronze + Duty Free + Gate escort' },
              { name:'Gold Departure (Arbel)', price:'TBD', desc:'Coming soon — April 2026' },
              { name:'Platinum Departure (Fattal)', price:'720', desc:'Private terminal · Lounge · Luxury to gate' },
            ]).map(pkg => (
              <button key={pkg.name} onClick={() => { s('vip_service',pkg.name); s('service_name',pkg.name); s('vip_price',pkg.price); if(pkg.price!=='TBD') s('total_price',pkg.price) }} style={{ border: f.vip_service===pkg.name ? '2px solid #B8860B' : '0.5px solid #ddd', borderRadius: 8, padding: '8px 10px', cursor: 'pointer', background: f.vip_service===pkg.name ? '#1a2a3a' : '#fff', textAlign: 'left' }}>
                <div style={{ fontSize: 11, fontWeight: 600, color: f.vip_service===pkg.name ? '#f5c842' : '#1a1a1a', marginBottom: 2 }}>{pkg.name}</div>
                <div style={{ fontSize: 10, color: f.vip_service===pkg.name ? '#aabbcc' : '#888', marginBottom: 3 }}>{pkg.desc}</div>
                <div style={{ fontSize: 13, fontWeight: 700, color: f.vip_service===pkg.name ? '#f5c842' : '#1a2a3a' }}>{pkg.price==='TBD' ? 'Coming soon' : `$${pkg.price}`}</div>
              </button>
            ))}
          </div>
        </div>
        <div style={g3}>
          <div><label style={lbl}>Airport</label><select style={inp}><option>Ben Gurion (TLV)</option><option>Eilat Ramon</option><option>Haifa</option></select></div>
          <div><label style={lbl}>Date</label><input type="date" style={inp} value={f.pickup_date} onChange={e => s('pickup_date',e.target.value)} /></div>
          <div><label style={lbl}>Meeting Time</label><input type="time" style={inp} value={f.meeting_time} onChange={e => s('meeting_time',e.target.value)} /></div>
        </div>
        <div style={g3}>
          <div><label style={lbl}>Flight No.</label><input style={inp} value={f.flight_number} onChange={e => s('flight_number',e.target.value)} placeholder="LY001..." /></div>
          <div><label style={lbl}>Terminal</label><input style={inp} placeholder="T1, T2, T3..." /></div>
          <div><label style={lbl}>No. of Passengers</label><input style={pre} value={travelers.length} readOnly /></div>
        </div>
      </>}

      {/* COMMON BOTTOM */}
      <div style={{ ...g3, marginTop: 10 }}>
        <div><label style={lbl}>Total Price ($)</label><input type="number" style={inp} value={f.total_price} onChange={e => s('total_price',e.target.value)} /></div>
        <div><label style={lbl}>Deposit ($)</label><input type="number" style={inp} value={f.deposit_paid} onChange={e => s('deposit_paid',e.target.value)} /></div>
        <div><label style={lbl}>Supplier Ref.</label><input style={inp} value={f.supplier_confirmation} onChange={e => s('supplier_confirmation',e.target.value)} /></div>
      </div>
      <div style={{ marginBottom: 10 }}>
        <label style={lbl}>Notes / Special Requests</label>
        <input style={inp} value={f.notes} onChange={e => s('notes',e.target.value)} placeholder="Special requests, important info..." />
      </div>

      <div style={{ display: 'flex', gap: 8 }}>
        <button onClick={() => onSave({
          type, client_id: clientId, file_number: fileNumber,
          service_name: f.service_name || `${type} booking`,
          check_in: f.check_in||null, check_out: f.check_out||null,
          pickup_date: f.pickup_date||null, return_date: f.return_date||null,
          num_travelers: parseInt(f.num_travelers)||travelers.length,
          total_price: parseFloat(f.total_price)||0,
          deposit_paid: parseFloat(f.deposit_paid)||0,
          supplier_confirmation: f.supplier_confirmation||null,
          notes: f.notes||null, status: existing?.status || 'inquiry', details: f
        })} style={{ padding: '7px 18px', background: '#1a2a3a', color: '#fff', border: 'none', borderRadius: 8, cursor: 'pointer', fontSize: 12, fontWeight: 600 }}>
          {existing ? 'Save Changes' : 'Save Booking'}
        </button>
        <button onClick={onCancel} style={{ padding: '7px 14px', background: '#fff', border: '0.5px solid #d0d0d0', borderRadius: 8, cursor: 'pointer', fontSize: 12 }}>Cancel</button>
      </div>
    </div>
  )
}
